using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiFetchTool
{
    [McpServerTool("fetch_external_data")]
    [Description("Fetches data from an external REST API endpoint.")]
    public static async Task<string> FetchExternalDataAsync(
        IHttpClientFactory httpClientFactory,
        [Description("The API path to query (e.g. \"/users/1\").")] string path,
        CancellationToken cancellationToken = default)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt("summarize")]
    [Description("Generates a prompt that asks the model to summarize the provided text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional desired length (e.g. \"one paragraph\", \"3 bullet points\").")] string? length = null)
    {
        var instruction = length is not null
            ? $"Summarize the following text in {length}."
            : "Summarize the following text concisely.";

        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content { Type = "text", Text = $"{instruction}\n\n{text}" }
            }
        ];
    }
}

